#!/usr/bin/env node
/**
 * Post-processes the Markdown file generated by db-schema-toolkit to inject
 * column-level comments from SCHEMA_COLUMN_COMMENTS into a "Commentaire" column.
 *
 * Usage (from repo root):
 *   npx tsx packages/app/scripts/post-process-schema-wiki.mjs
 *
 * Expects schema-doc.md in CWD (generated by db-schema-toolkit export).
 * Reads SCHEMA_COLUMN_COMMENTS from packages/app/src/server/db/schema-comments.ts
 * via tsx dynamic import.
 * Writes the enriched Markdown back to schema-doc.md (idempotent).
 */

import { readFileSync, writeFileSync, existsSync } from "node:fs";
import { pathToFileURL } from "node:url";
import { resolve } from "node:path";

const SCHEMA_DOC_PATH = resolve(process.cwd(), "schema-doc.md");
const SCHEMA_COMMENTS_PATH = resolve(
	process.cwd(),
	"packages/app/src/server/db/schema-comments.ts",
);

if (!existsSync(SCHEMA_DOC_PATH)) {
	console.error(`Error: schema-doc.md not found at ${SCHEMA_DOC_PATH}`);
	process.exit(1);
}

/** Convert camelCase to snake_case for map lookups (DB column names). */
function toSnakeCase(str) {
	return str
		.replace(/([A-Z]+)([A-Z][a-z])/g, "$1_$2")
		.replace(/([a-z\d])([A-Z])/g, "$1_$2")
		.toLowerCase();
}

/** Escape pipe characters inside a table cell value. */
function escapeCell(value) {
	return value.replace(/\|/g, "\\|");
}

/** Check if a line is a Markdown table separator (e.g. |---|---|). */
function isTableSeparator(line) {
	return /^\|[-| :]+\|$/.test(line.trim());
}

/** Parse a Markdown table row into an array of cell strings. */
function parseTableRow(line) {
	return line
		.trim()
		.replace(/^\|/, "")
		.replace(/\|$/, "")
		.split("|")
		.map((cell) => cell.trim());
}

/** Serialize cells back to a Markdown table row. */
function serializeTableRow(cells) {
	return `| ${cells.join(" | ")} |`;
}

async function main() {
	const { SCHEMA_COLUMN_COMMENTS } = await import(
		pathToFileURL(SCHEMA_COMMENTS_PATH).href
	);

	const input = readFileSync(SCHEMA_DOC_PATH, "utf8");
	const lines = input.split("\n");
	const output = [];

	let currentTable = null;
	let inTable = false;
	let headerProcessed = false;
	let commentaireColIndex = -1;
	let totalInjected = 0;
	const injectedByTable = {};

	for (let i = 0; i < lines.length; i++) {
		const line = lines[i];

		// Detect table header: ## Table: <name>
		const tableMatch = line.match(/^##\s+Table:\s+(.+)$/);
		if (tableMatch) {
			currentTable = tableMatch[1].trim();
			inTable = false;
			headerProcessed = false;
			commentaireColIndex = -1;
			output.push(line);
			continue;
		}

		// Detect start of a Markdown table (header row followed by separator)
		if (
			currentTable &&
			!inTable &&
			line.trim().startsWith("|") &&
			i + 1 < lines.length &&
			isTableSeparator(lines[i + 1])
		) {
			inTable = true;
			headerProcessed = false;
			const cells = parseTableRow(line);

			commentaireColIndex = cells.findIndex(
				(c) => c.toLowerCase() === "commentaire",
			);
			if (commentaireColIndex === -1) {
				output.push(serializeTableRow([...cells, "Commentaire"]));
			} else {
				output.push(line);
			}
			continue;
		}

		// Separator row (always follows the header row)
		if (inTable && !headerProcessed && isTableSeparator(line)) {
			headerProcessed = true;
			if (commentaireColIndex === -1) {
				const cells = parseTableRow(line);
				output.push(serializeTableRow([...cells, "---"]));
			} else {
				output.push(line);
			}
			continue;
		}

		// Data rows inside the table
		if (inTable && headerProcessed && line.trim().startsWith("|")) {
			const cells = parseTableRow(line);
			const columnName = cells[0];

			if (commentaireColIndex !== -1) {
				// Commentaire column already exists — update it if we have a comment
				if (currentTable && SCHEMA_COLUMN_COMMENTS[currentTable]) {
					const snakeKey = toSnakeCase(columnName);
					const comment =
						SCHEMA_COLUMN_COMMENTS[currentTable][snakeKey] ??
						SCHEMA_COLUMN_COMMENTS[currentTable][columnName] ??
						"";
					if (comment) {
						totalInjected++;
						injectedByTable[currentTable] =
							(injectedByTable[currentTable] ?? 0) + 1;
					}
					const updated = [...cells];
					updated[commentaireColIndex] = escapeCell(comment);
					output.push(serializeTableRow(updated));
				} else {
					output.push(line);
				}
			} else {
				// Always add the Commentaire cell (empty or filled)
				let comment = "";
				if (currentTable && SCHEMA_COLUMN_COMMENTS[currentTable]) {
					const snakeKey = toSnakeCase(columnName);
					comment =
						SCHEMA_COLUMN_COMMENTS[currentTable][snakeKey] ??
						SCHEMA_COLUMN_COMMENTS[currentTable][columnName] ??
						"";
					if (comment) {
						totalInjected++;
						injectedByTable[currentTable] =
							(injectedByTable[currentTable] ?? 0) + 1;
					}
				}
				output.push(serializeTableRow([...cells, escapeCell(comment)]));
			}
			continue;
		}

		// Non-table line resets table state
		if (inTable && !line.trim().startsWith("|")) {
			inTable = false;
			headerProcessed = false;
			commentaireColIndex = -1;
			// Note: keep currentTable set until the next ## Table: header
		}

		output.push(line);
	}

	writeFileSync(SCHEMA_DOC_PATH, output.join("\n"), "utf8");

	console.log(`\nPost-processing complete:`);
	console.log(`  Total comments injected: ${totalInjected}`);
	for (const [table, count] of Object.entries(injectedByTable)) {
		console.log(`  ${table}: ${count} comment(s)`);
	}

	// Warn about map entries whose table is not found in the Markdown
	const missingTables = [];
	for (const table of Object.keys(SCHEMA_COLUMN_COMMENTS)) {
		const tableHeader = lines.find((l) =>
			l.match(new RegExp(`^##\\s+Table:\\s+${table}\\s*$`)),
		);
		if (!tableHeader) {
			console.warn(
				`  WARN: table "${table}" in SCHEMA_COLUMN_COMMENTS not found in schema-doc.md`,
			);
			missingTables.push(table);
		}
	}
	if (missingTables.length > 0) {
		console.warn(
			`\n  ${missingTables.length} table(s) from the comments map were not found in the Markdown.`,
		);
		console.warn(`  This may indicate a table was renamed or removed.`);
	}
}

main().catch((err) => {
	console.error("Fatal error:", err.message);
	process.exit(1);
});
